// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.junit.jupiter.api.Test;

class CascadesEnforcerCompositionTest {

	@Test
	void orderingAndMaterializationReuseTheAuthoritativeGroup() {
		StatementPattern input = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
		PhysicalProperties required = PhysicalProperties.builder()
				.ordering(List.of("s:asc"))
				.materialization(PhysicalProperties.Materialization.MATERIALIZED)
				.build();
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.standardLogicalRules(), CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(input, OptimizationGoal.exact(required));

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics()::toString);
		assertTrue(plan.pendingTasks().isEmpty(), plan.pendingTasks()::toString);
		assertTrue(plan.winner().isPresent());
		assertFalse(plan.memo()
				.groups()
				.stream()
				.flatMap(group -> group.expressions().stream())
				.anyMatch(expression -> expression.logical()
						&& expression.tupleExpr() instanceof MaterializeTupleExpr),
				"an enforcer child must reference its source group instead of interning a Materialize marker");
		plan.memo()
				.groups()
				.stream()
				.flatMap(group -> group.expressions().stream())
				.filter(expression -> expression.kind() == RuleKind.ENFORCER)
				.forEach(expression -> assertEquals(List.of(expression.groupId()), expression.inputGroupIds(),
						"a unary property enforcer must recurse into its own group under a relaxed child goal"));
	}
}
